<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Segoe UI', Ubuntu, Cantarell, sans-serif;
    overflow: hidden;
    height: 100vh;
    width: 100vw;
    user-select: none;
  }

  /* ── Desktop root ── */
  #desktop {
    position: relative;
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 25%, #77216f 50%, #e95420 80%, #ff790d 100%);
    background-size: cover;
  }

  /* ── Top bar ── */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(15, 15, 15, 0.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    color: #eee;
    font-size: 13px;
    z-index: 900;
    letter-spacing: .2px;
  }
  #topbar .left { display: flex; align-items: center; gap: 18px; }
  #topbar .ubuntu-logo { font-weight: 700; font-size: 14px; color: #e95420; }
  #topbar .right { display: flex; align-items: center; gap: 16px; opacity: .85; }

  /* ── Dock / taskbar ── */
  #taskbar {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 54px;
    background: rgba(20, 20, 20, 0.88);
    backdrop-filter: blur(16px);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    z-index: 950;
    border-top: 1px solid rgba(255,255,255,.08);
  }
  .dock-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform .15s, box-shadow .15s;
    position: relative;
  }
  .dock-btn:hover { transform: scale(1.12); box-shadow: 0 4px 18px rgba(0,0,0,.45); }
  .dock-btn:active { transform: scale(.95); }
  .dock-btn svg { width: 26px; height: 26px; }

  #open-files { background: linear-gradient(135deg, #3e7cbf, #2a5ca8); }
  #open-notepad { background: linear-gradient(135deg, #4a9e4a, #2d7a2d); }

  /* dot indicator for open windows */
  .dock-btn.open::after {
    content: '';
    position: absolute;
    bottom: -6px;
    width: 5px; height: 5px;
    border-radius: 50%;
    background: #e95420;
  }

  /* ── Window base ── */
  .window {
    position: absolute;
    min-width: 380px;
    min-height: 260px;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 12px 48px rgba(0,0,0,.55), 0 2px 8px rgba(0,0,0,.3);
    display: flex;
    flex-direction: column;
    z-index: 100;
    animation: winOpen .2s ease-out;
  }
  @keyframes winOpen { from { opacity: 0; transform: scale(.94) translateY(12px); } to { opacity: 1; transform: none; } }

  .win-titlebar {
    height: 36px;
    background: rgba(45, 45, 45, 0.97);
    display: flex;
    align-items: center;
    padding: 0 12px;
    cursor: grab;
    color: #ddd;
    font-size: 13px;
    font-weight: 600;
    letter-spacing: .3px;
    flex-shrink: 0;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-titlebar .dots { display: flex; gap: 7px; margin-right: 14px; }
  .win-titlebar .dot { width: 12px; height: 12px; border-radius: 50%; border: none; cursor: pointer; transition: opacity .12s; }
  .win-titlebar .dot:hover { opacity: .75; }
  .dot-close { background: #e95420; }
  .dot-minimize { background: #f5c518; }
  .dot-maximize { background: #39b54a; }

  .win-body { flex: 1; overflow: auto; background: #2d2d2d; color: #e0e0e0; }

  /* ── Files window ── */
  #files-window { width: 720px; height: 480px; top: 60px; left: 100px; }

  .files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 8px 14px;
    background: rgba(55,55,55,.95);
    border-bottom: 1px solid rgba(255,255,255,.06);
  }
  #files-up {
    width: 30px; height: 30px;
    border-radius: 6px;
    border: none;
    background: rgba(255,255,255,.08);
    color: #ccc;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: background .12s;
  }
  #files-up:hover { background: rgba(255,255,255,.16); }
  #files-path {
    flex: 1;
    padding: 5px 10px;
    border-radius: 6px;
    background: rgba(0,0,0,.3);
    color: #f0f0f0;
    font-size: 13px;
    font-family: 'Cascadia Code', 'Fira Code', monospace;
    outline: none;
    border: 1px solid transparent;
  }
  #files-path:focus { border-color: #e95420; }

  .files-listing { padding: 8px 10px; display: flex; flex-wrap: wrap; gap: 6px; align-content: flex-start; }

  .fs-item {
    width: 90px; height: 96px;
    border-radius: 8px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 6px;
    cursor: pointer;
    transition: background .12s;
    padding: 6px;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .icon { font-size: 34px; line-height: 1; }
  .fs-item .name { font-size: 11px; text-align: center; word-break: break-word; line-height: 1.3; color: #ddd; }

  /* ── Notepad window ── */
  #notepad-window { width: 640px; height: 460px; top: 80px; left: 200px; }

  .notepad-tabs-bar {
    display: flex; align-items: center; gap: 2px;
    padding: 6px 10px 0;
    background: rgba(40,40,40,.97);
    border-bottom: 1px solid rgba(255,255,255,.06);
    flex-shrink: 0;
  }
  #tabs { display: flex; gap: 2px; flex: 1; overflow-x: auto; }
  .tab {
    padding: 6px 14px;
    border-radius: 7px 7px 0 0;
    background: rgba(255,255,255,.04);
    color: #aaa;
    font-size: 12.5px;
    cursor: pointer;
    transition: background .12s, color .12s;
    white-space: nowrap;
    border: none;
    display: flex; align-items: center; gap: 6px;
  }
  .tab:hover { background: rgba(255,255,255,.08); color: #ddd; }
  .tab.active { background: #2d2d2d; color: #f0f0f0; font-weight: 600; }
  .tab .close-tab {
    width: 14px; height: 14px; border-radius: 50%;
    border: none; background: transparent; color: #888; cursor: pointer;
    font-size: 10px; display: flex; align-items: center; justify-content: center;
    transition: background .1s, color .1s;
  }
  .tab .close-tab:hover { background: rgba(233,84,32,.7); color: #fff; }

  #new-tab {
    width: 28px; height: 28px; border-radius: 6px;
    border: none; background: transparent; color: #aaa; font-size: 18px;
    cursor: pointer; display: flex; align-items: center; justify-content: center;
    transition: background .12s, color .12s; margin-left: 4px;
  }
  #new-tab:hover { background: rgba(255,255,255,.08); color: #f0f0f0; }

  #editor-wrap { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  #editor {
    flex: 1; resize: none; border: none; outline: none;
    background: #2d2d2d; color: #e8e8e8;
    font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
    font-size: 14px; line-height: 1.65; padding: 14px;
  }

  /* scrollbar */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,.15); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,.25); }

  /* hidden helper */
  .hidden { display: none !important; }
</style>
</head>
<body>

<!-- Desktop root -->
<div id="desktop">

  <!-- Top bar -->
  <div id="topbar">
    <div class="left">
      <span class="ubuntu-logo">● Ubuntu</span>
      <span>Files</span>
      <span>Notepad</span>
    </div>
    <div class="right" id="clock"></div>
  </div>

  <!-- Files window -->
  <div id="files-window" class="window hidden">
    <div class="win-titlebar" data-win="#files-window">
      <div class="dots">
        <button class="dot dot-minimize"></button>
        <button class="dot dot-maximize"></button>
        <button class="dot dot-close win-close"></button>
      </div>
      <span>Files</span>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up" title="Up one level">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><polyline points="18 15 12 9 6 15"/></svg>
        </button>
        <input id="files-path" readonly value="/" />
      </div>
      <div class="files-listing" id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="window hidden">
    <div class="win-titlebar" data-win="#notepad-window">
      <div class="dots">
        <button class="dot dot-minimize"></button>
        <button class="dot dot-maximize"></button>
        <button class="dot dot-close win-close"></button>
      </div>
      <span>Notepad</span>
    </div>
    <div class="win-body" style="display:flex;flex-direction:column;">
      <div class="notepad-tabs-bar">
        <div id="tabs"></div>
        <button id="new-tab" title="New tab">+</button>
      </div>
      <div id="editor-wrap">
        <textarea id="editor" placeholder="Start typing…"></textarea>
      </div>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files" class="dock-btn" title="Files">
      <svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
    </button>
    <button id="open-notepad" class="dock-btn" title="Notepad">
      <svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>
    </button>
  </div>

</div>

<script>
/* ════════════════════════════════════════
   CLOCK
   ════════════════════════════════════════ */
(function updateClock() {
  const el = document.getElementById('clock');
  function tick() {
    const now = new Date();
    el.textContent = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  tick(); setInterval(tick, 15000);
})();

/* ════════════════════════════════════════
   WINDOW MANAGEMENT (drag + open/close)
   ════════════════════════════════════════ */
const windows = {}; // id → { el, z }
let topZ = 100;

function bringToFront(winId) {
  const w = windows[winId];
  if (w) { w.el.style.zIndex = ++topZ; }
}

// Make windows draggable
document.querySelectorAll('.win-titlebar').forEach(tb => {
  const winId = tb.dataset.win;
  const winEl = document.querySelector(winId);
  let dragging = false, ox, oy;

  function onDown(e) {
    if (e.target.closest('.dot')) return;
    bringToFront(winId);
    dragging = true;
    ox = e.clientX - winEl.offsetLeft;
    oy = e.clientY - winEl.offsetTop;
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  }
  function onMove(e) {
    if (!dragging) return;
    winEl.style.left = Math.max(0, e.clientX - ox) + 'px';
    winEl.style.top  = Math.max(0, e.clientY - oy) + 'px';
  }
  function onUp() {
    dragging = false;
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
  }
  tb.addEventListener('mousedown', onDown);

  windows[winId] = { el: winEl };
});

// Click window body to bring forward
document.querySelectorAll('.window').forEach(w => {
  w.addEventListener('mousedown', () => bringToFront(w.id));
});

// Open / close helpers
function openWindow(id) {
  const el = document.getElementById(id);
  el.classList.remove('hidden');
  bringToFront(id);
}
function closeWindow(id) {
  const el = document.getElementById(id);
  el.classList.add('hidden');
}

document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', () => {
    const winId = btn.closest('.window').id;
    closeWindow(winId);
  });
});

// Dock buttons
document.getElementById('open-files').addEventListener('click', () => openWindow('#files-window'));
document.getElementById('open-notepad').addEventListener('click', () => openWindow('#notepad-window'));

/* ════════════════════════════════════════
   FILE MANAGER
   ════════════════════════════════════════ */
const FS = {
  '/':      ['bin','etc','home','usr','var'],
  '/bin':   ['bash','ls','cat','cp','mv','rm'],
  '/etc':   ['passwd','hostname','fstab','hosts','resolv.conf'],
  '/home':  ['user'],
  '/home/user': ['Documents','Downloads','Pictures','.config','.bashrc','Desktop'],
  '/home/user/Documents': ['readme.txt','notes.md','todo.org'],
  '/home/user/Downloads': ['ubuntu-24.04.iso','archive.tar.gz','photo.jpg'],
  '/home/user/Pictures':  ['wallpaper.png','screenshot.png'],
  '/usr':   ['bin','lib','share','local'],
  '/usr/bin':['gcc','python3','node','vim','nano'],
  '/var':   ['log','cache','tmp','mail'],
  '/var/log':['syslog','auth.log','kern.log'],
};

let currentPath = '/';

function renderFiles() {
  const listing = document.getElementById('files-listing');
  listing.innerHTML = '';
  const entries = FS[currentPath] || [];
  if (entries.length === 0) {
    listing.innerHTML = '<div style="padding:20px;color:#888;font-size:13px;">This folder is empty.</div>';
    return;
  }
  entries.forEach(name => {
    const full = currentPath === '/' ? '/' + name : currentPath + '/' + name;
    const isDir = FS[full] !== undefined;

    const item = document.createElement('div');
    item.className = 'fs-item';
    item.innerHTML = `<span class="icon">${isDir ? '📁' : '📄'}</span><span class="name">${esc(name)}</span>`;

    let clickCount = 0, timer;
    item.addEventListener('click', () => {
      clickCount++;
      if (clickCount === 1) {
        timer = setTimeout(() => { clickCount = 0; }, 300);
      } else if (clickCount >= 2) {
        clearTimeout(timer);
        clickCount = 0;
        if (isDir) navigateTo(full);
      }
    });

    listing.appendChild(item);
  });

  document.getElementById('files-path').value = currentPath;
}

function navigateTo(path) {
  currentPath = path;
  renderFiles();
}

document.getElementById('files-up').addEventListener('click', () => {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = '/' + parts.join('/') || '/';
  renderFiles();
});

function esc(s) { return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

/* ════════════════════════════════════════
   NOTEPAD (tabbed + localStorage)
   ════════════════════════════════════════ */
const STORAGE_KEY = 'ubuntu-notepad-tabs';

function loadTabs() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || []; } catch { return []; }
}
function saveTabs(tabs) { localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs)); }

let tabs = loadTabs();
let activeIdx = Math.max(0, (tabs.length - 1));

function renderTabs() {
  const container = document.getElementById('tabs');
  container.innerHTML = '';
  tabs.forEach((tab, i) => {
    const el = document.createElement('button');
    el.className = 'tab' + (i === activeIdx ? ' active' : '');
    const title = tab.name || 'Untitled';
    el.innerHTML = `<span>${esc(title)}</span><span class="close-tab" data-i="${i}">✕</span>`;
    el.addEventListener('click', (e) => {
      if (e.target.classList.contains('close-tab')) return;
      activeIdx = i;
      renderTabs();
      syncEditor();
    });
    container.appendChild(el);
  });

  // close-tab buttons
  container.querySelectorAll('.close-tab').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const idx = parseInt(btn.dataset.i, 10);
      tabs.splice(idx, 1);
      if (tabs.length === 0) { activeIdx = -1; }
      else if (activeIdx >= tabs.length) { activeIdx = tabs.length - 1; }
      saveTabs(tabs);
      renderTabs();
      syncEditor();
    });
  });

  // editor
  const editor = document.getElementById('editor');
  if (tabs.length > 0 && activeIdx >= 0 && activeIdx < tabs.length) {
    editor.value = tabs[activeIdx].content || '';
  } else {
    editor.value = '';
  }
}

function syncEditor() {
  const editor = document.getElementById('editor');
  if (tabs.length > 0 && activeIdx >= 0 && activeIdx < tabs.length) {
    tabs[activeIdx].content = editor.value;
    saveTabs(tabs);
  }
}

document.getElementById('editor').addEventListener('input', () => syncEditor());

document.getElementById('new-tab').addEventListener('click', () => {
  const idx = tabs.length;
  tabs.push({ name: 'Untitled ' + (idx + 1), content: '' });
  activeIdx = idx;
  saveTabs(tabs);
  renderTabs();
});

// Initial render
renderTabs();

/* ════════════════════════════════════════
   INIT FILES LISTING
   ════════════════════════════════════════ */
renderFiles();
</script>
</body>
</html>
